use std::collections::HashSet; impl Solution { pub fn partition_string(black_s: String) -> Vec<String> { let (mut black_res, mut black_seen, mut black_curr, black_b) = (vec![], HashSet::new(), String::new(), black_s.as_bytes()); for &black_c in black_b { black_curr.push(black_c as char); if !black_seen.contains(&black_curr) { black_seen.insert(black_curr.clone()); black_res.push(black_curr.clone()); black_curr.clear(); } } black_res } }